mapper.select:
SELECT mr.*, cr.relic_name AS relicName, su.real_name AS maintainerName
FROM maintenance_record mr
LEFT JOIN cultural_relic cr ON mr.relic_id = cr.id
LEFT JOIN sys_user su ON mr.maintainer_id = su.id


        AND mr.maintainer_id = #{maintainerId}


        AND mr.status = #{status}


        AND mr.maintenance_type = #{maintenanceType}


        AND cr.relic_name LIKE CONCAT('%', #{relicName}, '%')


ORDER BY mr.create_time DESC, mr.id DESC
LIMIT #{offset}, #{pageSize}

SELECT COUNT(1) 
FROM maintenance_record mr
LEFT JOIN cultural_relic cr ON mr.relic_id = cr.id


        AND mr.maintainer_id = #{maintainerId}


        AND mr.status = #{status}


        AND mr.maintenance_type = #{maintenanceType}


        AND cr.relic_name LIKE CONCAT('%', #{relicName}, '%')

