relic_id = #{relicId}, maintenance_type = #{maintenanceType}, maintenance_date = #{maintenanceDate}, maintenance_content = #{maintenanceContent}, maintainer_id = #{maintainerId}, status = #{status}, approver = #{approver}, approve_date = #{approveDate}, approve_remark = #{approveRemark}, remark = #{remark}, update_time = NOW()
